export function toEnglish(value: string): string {
  const trimmed = value.trim();
  const direct = englishCopy[trimmed];
  if (direct) return value.replace(trimmed, direct);
  return value
    .replace(/(\d+) profils? affichés?/g, '$1 profiles displayed')
    .replace(/(\d+) profils? dans la zone/g, '$1 profiles in this region')
    .replace(/(\d+) profils? dans votre sélection/g, '$1 profiles in your shortlist')
    .replace(/Profil (\d+) \/ (\d+)/g, 'Profile $1 / $2')
    .replace(/(\d+) créateurs? sélectionnés?/g, '$1 selected creators')
    .replace(/(\d+) profils?/g, '$1 profiles')
    .replace(/(\d+) résultats?/g, '$1 results')
    .replace(/^Expertise (.+)$/, (_match, detail: string) => `Expertise: ${toEnglish(detail)}`)
    .replace(/^Formats adaptés : (.+)$/, (_match, detail: string) => `Suitable formats: ${detail.split(', ').map(toEnglish).join(', ')}`)
    .replace(/^Présence : (.+)$/, (_match, detail: string) => `Presence: ${toEnglish(detail)}`)
    .replace(/(\d[\d,.\s]*[KkMm]?) abonnés/g, '$1 followers')
    .replace(/Retirer (.+)/, 'Remove $1')
    .replace(/Ouvrir le média (\d+)/, 'Open media $1')
    .replace(/Aperçu éditorial (\d+) (?:pour|de) (.+)/, 'Editorial preview $1 for $2')
    .replace(/Galerie de (.+)/, '$1 gallery');
}
